import{_ as o,c as t,o as r,a1 as s}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"À propos | Introduction à OpenCodeDocs | opencodedocs","description":"Découvrez OpenCodeDocs, le premier site de tutoriels de l'écosystème IA. Analyse approfondie des projets open source avec des tutoriels de haute qualité basés sur le code source et 100% exécutables.","frontmatter":{"title":"À propos | Introduction à OpenCodeDocs | opencodedocs","sidebarTitle":"Découvrir la vision du projet","subtitle":"À propos | Introduction à OpenCodeDocs | opencodedocs","description":"Découvrez OpenCodeDocs, le premier site de tutoriels de l'écosystème IA. Analyse approfondie des projets open source avec des tutoriels de haute qualité basés sur le code source et 100% exécutables."},"headers":[],"relativePath":"fr/about.md","filePath":"fr/about.md"}`),n={name:"fr/about.md"};function a(i,e,c,l,u,d){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="a-propos-d-opencodedocs" tabindex="-1">À propos d&#39;OpenCodeDocs <a class="header-anchor" href="#a-propos-d-opencodedocs" aria-label="Permalink to &quot;À propos d&#39;OpenCodeDocs&quot;">​</a></h1><blockquote><p><strong>Premier site de tutoriels de l&#39;écosystème IA · Basé sur le code source · 100% exécutable</strong></p></blockquote><h2 id="notre-vision" tabindex="-1">Notre vision <a class="header-anchor" href="#notre-vision" aria-label="Permalink to &quot;Notre vision&quot;">​</a></h2><p>Les outils IA évoluent rapidement, la documentation officielle prend du retard et les tutoriels en ligne sont obsolètes — nous voulons changer tout ça.</p><p>OpenCodeDocs analyse en profondeur le code source des projets open source et les exemples officiels, extrait la logique principale, et garantit que chaque ligne de code fonctionne grâce à une vérification automatisée.</p><p>Lorsque les projets sont mis à jour, nos tutoriels sont également synchronisés. Chaque tutoriel indique clairement la version Git Commit, pour que vous sachiez sur quelle version le code est basé.</p><p><strong>Notre objectif est de devenir la « Verified Standard » de l&#39;écosystème des outils IA.</strong></p><h2 id="licence-open-source" tabindex="-1">Licence open source <a class="header-anchor" href="#licence-open-source" aria-label="Permalink to &quot;Licence open source&quot;">​</a></h2><p>Nous croyons que l&#39;ouverture apporte la confiance. Les contributions de la communauté, les corrections et les compléments sont les bienvenus.</p><h3 id="contenu-des-tutoriels" tabindex="-1">Contenu des tutoriels <a class="header-anchor" href="#contenu-des-tutoriels" aria-label="Permalink to &quot;Contenu des tutoriels&quot;">​</a></h3><p><strong>Licence</strong>: <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/deed.fr" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a><br> Attribution - Pas d&#39;utilisation commerciale - Partage dans les mêmes conditions. La reproduction et l&#39;adaptation sont autorisées, mais la source doit être indiquée, l&#39;utilisation commerciale est interdite, et le partage doit se faire sous les mêmes conditions.</p><h3 id="outil-de-construction" tabindex="-1">Outil de construction <a class="header-anchor" href="#outil-de-construction" aria-label="Permalink to &quot;Outil de construction&quot;">​</a></h3><p><strong>VitePress</strong>: Ce projet est construit avec <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a>.<br> Nous remercions l&#39;équipe VitePress de fournir un générateur de sites statiques aussi excellent.</p><p><a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">Voir le dépôt GitHub</a></p><h2 id="contactez-nous" tabindex="-1">Contactez-nous <a class="header-anchor" href="#contactez-nous" aria-label="Permalink to &quot;Contactez-nous&quot;">​</a></h2><ul><li><strong>E-mail</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Twitter</strong>: <a href="https://x.com/codingzys" target="_blank" rel="noreferrer">@codingzys</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">github.com/vbgate/opencodedocs</a></li></ul>',16)])])}const h=o(n,[["render",a]]);export{m as __pageData,h as default};
